      })
      return { ...state, boms, lastUpdated: now }
    }

    // --- LMAT 2.0: Documentos ---
    case "ADD_ARTICLE_DOCUMENT": {
      const articles = state.articles.map(a => {
        if (a.id !== action.payload.articleId) return a
        const documents = [...(a.documents || []), action.payload.document]
