        const documents = (a.documents || []).map(d =>
          d.id === action.payload.documentId ? { ...d, ...action.payload.updates } : d
        )
        return { ...a, documents, updatedAt: now.split("T")[0] }
      })
      return { ...state, articles, lastUpdated: now }
