      return { ...state, currentUser: action.payload }
    case "SET_CURRENT_PLANT":
      return { ...state, currentPlant: action.payload }

    // --- Audit ---
    case "ADD_AUDIT_LOG":
      return { ...state, auditLog: [action.payload, ...state.auditLog].slice(0, 500) }

    // --- Hydrate ---
    case "HYDRATE":
      return action.payload

    default:
