	let validationNotes = $state('');
	let validationStatus = $state<DepartmentValidationStatus>('completado');
	let selectedDepartment = $state('');
	let dialogOpen = $state(false);

	// BOMs pending validation (estabilizado status, not all departments completed)
	const bomsForValidation = $derived(
		state.boms.filter((bom: BOM) => {
			if (bom.maturityStatus === 'liberado' || bom.maturityStatus === 'obsoleto') return false;
			if (bom.maturityStatus === 'en_desarrollo') return false;
			return true;
		})
	);

	// Stats by department
	const departmentStats = $derived(
		VALIDATION_DEPARTMENTS.map((dept) => {
			const pending = bomsForValidation.filter((bom: BOM) => {
				const validation = bom.departmentValidations?.find((v: any) => v.department === dept);
				return !validation || validation.status === 'pendiente';
			}).length;
			const completed = bomsForValidation.filter((bom: BOM) => {
				const validation = bom.departmentValidations?.find((v: any) => v.department === dept);
				return validation?.status === 'completado';
			}).length;
			const rejected = bomsForValidation.filter((bom: BOM) => {
				const validation = bom.departmentValidations?.find((v: any) => v.department === dept);
				return validation?.status === 'rechazado';
			}).length;
			return { department: dept, pending, completed, rejected, total: bomsForValidation.length };
		})
	);

	// Overall progress
	const totalValidations = $derived(bomsForValidation.length * VALIDATION_DEPARTMENTS.length);
	const completedValidations = $derived(
		bomsForValidation.reduce((acc: number, bom: BOM) => {
			return acc + (bom.departmentValidations?.filter((v: any) => v.status === 'completado').length || 0);
		}, 0)
	);
	const overallProgress = $derived(totalValidations > 0 ? (completedValidations / totalValidations) * 100 : 0);

	function handleValidation() {
		if (!selectedBOM || !selectedDepartment) return;

		store.dispatch({
			type: 'UPDATE_BOM_VALIDATION',
			payload: {
				bomId: selectedBOM.id,
				department: selectedDepartment,
				status: validationStatus,
				notes: validationNotes
			}
		});

		dialogOpen = false;
		validationNotes = '';
		selectedBOM = null;
		selectedDepartment = '';
	}

	function openValidationDialog(bom: BOM, dept: string) {
		selectedBOM = bom;
		selectedDepartment = dept;
		validationStatus = 'completado';
		validationNotes = '';
		dialogOpen = true;
	}

	function getValidationForDept(bom: BOM, dept: string) {
		return bom.departmentValidations?.find((v: any) => v.department === dept);
	}

	function getBOMProgress(bom: BOM) {
		const completed = bom.departmentValidations?.filter((v: any) => v.status === 'completado').length || 0;
		return (completed / VALIDATION_DEPARTMENTS.length) * 100;
	}

	const estabilizadoCount = $derived(bomsForValidation.filter((b: BOM) => b.maturityStatus === 'estabilizado').length);
	const preliminarCount = $derived(bomsForValidation.filter((b: BOM) => b.maturityStatus === 'preliminar').length);
	const liberadoCount = $derived(state.boms.filter((b: BOM) => b.maturityStatus === 'liberado').length);
</script>

