<script lang="ts">
	import { useStore } from '$lib/tps/store.svelte.js';
	import { VEHICLE_MODELS, ARMOR_LEVEL_LABELS, PLANT_CELLS, UDM_LABELS } from '$lib/tps/constants.ts';
	import { generateId } from '$lib/tps/utils.ts';
	import { goto } from '$app/navigation';
	import type { BOMComponent, ArmorLevel, Plant } from '$lib/tps/types.ts';
	import ArrowLeft from '@lucide/svelte/icons/arrow-left';
	import Save from '@lucide/svelte/icons/save';
	import Plus from '@lucide/svelte/icons/plus';
	import Trash2 from '@lucide/svelte/icons/trash-2';
	import Search from '@lucide/svelte/icons/search';

	const store = useStore();
	const state = $derived(store.state);
	const defaultPlant = $derived(state.currentPlant !== 'todas' ? state.currentPlant : 'planta_1') as Plant;

	let form = $state({
		specificationCode: '',
		vehicleModel: VEHICLE_MODELS[0],
		armorLevel: 'NIII' as ArmorLevel,
		plant: defaultPlant
	});
	let components = $state<BOMComponent[]>([]);
	let errors = $state<string[]>([]);
	let searchQ = $state('');
	let showSearch = $state(false);

	const matchingArticles = $derived.by(() => {
		if (searchQ.length < 2) return [];
		return state.articles
			.filter(a => `${a.code} ${a.description}`.toLowerCase().includes(searchQ.toLowerCase()))
			.slice(0, 8);
	});

	const cells = $derived(PLANT_CELLS[form.plant as Plant] || []);

	function addComponent(articleId: string) {
		const article = state.articles.find(a => a.id === articleId);
		if (!article) return;
		if (components.some(c => c.articleId === articleId)) return;

		components.push({
			id: generateId(),
			articleId,
			articleCode: article.code,
			articleDescription: article.description,
			quantity: 1,
			udm: article.udmBase,
			cell: cells[0] || 'Celda 1',
			operation: '',
			notes: '',
			hasCompleteData: article.completeness >= 80,
			parentId: null,
			order: components.length,
			level: 0,
			isKit: false
		});
		searchQ = '';
		showSearch = false;
	}

	function removeComponent(id: string) {
		components = components.filter(c => c.id !== id);
	}

	function updateComponent(id: string, field: keyof BOMComponent, value: unknown) {
		const idx = components.findIndex(c => c.id === id);
		if (idx >= 0) {
			components[idx] = { ...components[idx], [field]: value };
		}
	}

	function validate(): string[] {
		const errs: string[] = [];
		if (!form.specificationCode.trim()) errs.push('Codigo de especificacion es obligatorio');
		if (state.boms.some(b => b.specificationCode === form.specificationCode.trim()))
			errs.push('Ya existe un BOM con este codigo');
		if (components.length === 0) errs.push('Agrega al menos un componente');
		return errs;
	}

	function handleSave() {
		const errs = validate();
		if (errs.length > 0) {
			errors = errs;
			return;
		}

		const bom = {
			id: generateId(),
			specificationCode: form.specificationCode.trim(),
			vehicleModel: form.vehicleModel,
			armorLevel: form.armorLevel,
			plant: form.plant as Plant,
			version: 1,
			status: 'borrador' as const,
			maturityStatus: 'en_desarrollo' as const,
			components,
			revisions: [],
			healthPercent: 0,
			departmentValidations: [],
			specificationId: null,
			plantRoutes: [],
			cuttingKitIds: [],
			createdAt: new Date().toISOString().split('T')[0],
			updatedAt: new Date().toISOString().split('T')[0],
			createdBy: state.currentUser.name
		};

		store.dispatch({ type: 'ADD_BOM', payload: bom });
		store.dispatch({
			type: 'ADD_AUDIT_LOG',
			payload: {
				id: generateId(),
				userId: state.currentUser.id,
				userName: state.currentUser.name,
				entity: 'BOM',
				entityId: bom.id,
				action: 'crear',
				field: 'nuevo',
				oldValue: '',
				newValue: bom.specificationCode,
				timestamp: new Date().toISOString()
			}
		});

		goto('/lmat/boms');
	}
</script>

