	import ArrowLeft from '@lucide/svelte/icons/arrow-left';
	import Save from '@lucide/svelte/icons/save';

	const store = useStore();
	const state = $derived(store.state);
	const defaultPlant = $derived(state.currentPlant !== 'todas' ? state.currentPlant : 'planta_1') as Plant;

	let form = $state({
		folioTPS: '',
		vehicleModel: VEHICLE_MODELS[0],
		armorLevel: 'NIII' as ArmorLevel,
		clientId: state.clients[0]?.id || '',
		plant: defaultPlant,
		quotationAmount: 0,
		bomId: ''
	});
	let errors = $state<string[]>([]);

	function validate(): string[] {
		const errs: string[] = [];
		if (!form.folioTPS.trim()) errs.push('Folio TPS es obligatorio');
		if (!/^\d{4}$/.test(form.folioTPS.trim())) errs.push('Folio TPS debe ser de 4 digitos');
		if (state.projects.some(p => p.folioTPS === form.folioTPS.trim()))
			errs.push('Ya existe un proyecto con este folio');
		if (!form.clientId) errs.push('Selecciona un cliente');
		return errs;
	}

	function handleSave() {
		const errs = validate();
		if (errs.length > 0) {
			errors = errs;
			return;
		}

		const client = state.clients.find(c => c.id === form.clientId);
		const stages = PROJECT_STAGE_ORDER.map(s => ({
			name: s as ProjectStatus,
			label: PROJECT_STATUS_LABELS[s as ProjectStatus],
			startedAt: s === 'cotizacion' ? new Date().toISOString().split('T')[0] : null,
			completedAt: null,
			isActive: s === 'cotizacion',
			notes: ''
		}));

		const project = {
			id: generateId(),
			folioTPS: form.folioTPS.trim(),
			vehicleModel: form.vehicleModel,
			armorLevel: form.armorLevel,
			clientId: form.clientId,
			clientName: client?.name || '',
			plant: form.plant as Plant,
			status: 'cotizacion' as const,
			quotationAmount: form.quotationAmount,
			stages,
			costs: [],
			documents: [],
			bomId: form.bomId || null,
			daysInProduction: 0,
			progressPercent: 0,
			totalCost: 0,
			estimatedMargin: 0,
			createdAt: new Date().toISOString().split('T')[0],
			updatedAt: new Date().toISOString().split('T')[0]
		};

		store.dispatch({ type: 'ADD_PROJECT', payload: project });
		store.dispatch({
			type: 'ADD_AUDIT_LOG',
			payload: {
				id: generateId(),
				userId: state.currentUser.id,
				userName: state.currentUser.name,
				entity: 'Project',
				entityId: project.id,
				action: 'crear',
				field: 'nuevo',
				oldValue: '',
				newValue: project.folioTPS,
				timestamp: new Date().toISOString()
			}
		});

		goto(`/proyectos/${project.id}`);
	}
</script>

