```svelte
<script lang="ts">
	import { useStore } from '$lib/tps/store.svelte.js';
	import StatusBadge from '$lib/tps/components/status-badge.svelte';
	import {
		BOM_STATUS_LABELS,
		BOM_STATUS_COLORS,
		ARMOR_LEVEL_LABELS,
		PLANT_LABELS,
		BOM_MATURITY_LABELS,
		BOM_MATURITY_COLORS
	} from '$lib/tps/constants.js';
	import type { BOMStatus, BOMMaturityStatus } from '$lib/tps/types.js';
	import Search from '@lucide/svelte/icons/search';
	import ArrowUpDown from '@lucide/svelte/icons/arrow-up-down';
	import ChevronUp from '@lucide/svelte/icons/chevron-up';
	import ChevronDown from '@lucide/svelte/icons/chevron-down';
	import Plus from '@lucide/svelte/icons/plus';
	import ArrowLeft from '@lucide/svelte/icons/arrow-left';

	type SortField =
		| 'specificationCode'
		| 'vehicleModel'
		| 'armorLevel'
		| 'version'
		| 'healthPercent'
		| 'components';
	type SortDir = 'asc' | 'desc';

	const store = useStore();
	const state = $derived(store.state);

	let query = $state('');
	let statusFilter = $state<BOMStatus | 'todos'>('todos');
	let maturityFilter = $state<BOMMaturityStatus | 'todos'>('todos');
	let sortField = $state<SortField>('specificationCode');
	let sortDir = $state<SortDir>('asc');

	const filtered = $derived.by(() => {
		let items = state.boms;
		if (state.currentPlant !== 'todas') items = items.filter((b) => b.plant === state.currentPlant);
		if (query)
			items = items.filter((b) =>
				`${b.specificationCode} ${b.vehicleModel}`.toLowerCase().includes(query.toLowerCase())
			);
		if (statusFilter !== 'todos') items = items.filter((b) => b.status === statusFilter);
		if (maturityFilter !== 'todos') items = items.filter((b) => b.maturityStatus === maturityFilter);

		return [...items].sort((a, b) => {
			let cmp = 0;
			switch (sortField) {
				case 'specificationCode':
					cmp = a.specificationCode.localeCompare(b.specificationCode);
					break;
				case 'vehicleModel':
					cmp = a.vehicleModel.localeCompare(b.vehicleModel);
					break;
				case 'armorLevel':
					cmp = a.armorLevel.localeCompare(b.armorLevel);
					break;
				case 'version':
					cmp = a.version - b.version;
					break;
				case 'healthPercent':
					cmp = a.healthPercent - b.healthPercent;
					break;
				case 'components':
					cmp = a.components.length - b.components.length;
					break;
			}
			return sortDir === 'asc' ? cmp : -cmp;
		});
	});

	function toggleSort(field: SortField) {
		if (sortField === field) {
			sortDir = sortDir === 'asc' ? 'desc' : 'asc';
		} else {
			sortField = field;
			sortDir = 'asc';
		}
	}

	const totalBOMs = $derived(state.boms.length);
	const released = $derived(state.boms.filter((b) => b.maturityStatus === 'liberado').length);
	const avgHealth = $derived(
		Math.round(state.boms.reduce((s, b) => s + b.healthPercent, 0) / (totalBOMs || 1))
	);
	const totalComponents = $derived(state.boms.reduce((s, b) => s + b.components.length, 0));
</script>

