								{/if}
							</span>
						</th>
						<th
							class="px-4 py-2.5 text-xs font-medium text-muted-foreground cursor-pointer"
							onclick={() => toggleSort('vehicleModel')}
						>
							<span class="flex items-center gap-1">
								Modelo
								{#if sortField !== 'vehicleModel'}
									<ArrowUpDown class="h-3 w-3 opacity-30" />
								{:else if sortDir === 'asc'}
									<ChevronUp class="h-3 w-3" />
								{:else}
									<ChevronDown class="h-3 w-3" />
								{/if}
							</span>
						</th>
						<th class="px-4 py-2.5 text-xs font-medium text-muted-foreground">Nivel</th>
						<th class="px-4 py-2.5 text-xs font-medium text-muted-foreground">Planta</th>
						<th
							class="px-4 py-2.5 text-xs font-medium text-muted-foreground text-center cursor-pointer"
