					class="hover:bg-primary/90 flex items-center gap-1.5 rounded-md bg-primary px-3 py-1.5 text-xs font-medium text-primary-foreground transition-colors"
				>
					<Plus class="h-3.5 w-3.5" /> Crear Version
				</button>
				<select
					value={bom.status}
					onchange={(e) => handleStatusChange((e.currentTarget as HTMLSelectElement).value as BOMStatus)}
					class="text-foreground border-border rounded-md border bg-secondary px-2 py-1.5 text-xs outline-none"
				>
					{#each Object.entries(BOM_STATUS_LABELS) as [k, v]}
						<option value={k}>{v}</option>
					{/each}
				</select>
			</div>
		</div>

		<!-- LMAT 2.0: Maturity Status + Quick Info -->
		<div class="border-border overflow-hidden rounded-lg border bg-card">
			<div class="border-border flex items-center justify-between border-b bg-secondary/30 px-4 py-3">
				<div class="flex items-center gap-3">
					<ShieldCheck class="text-primary h-5 w-5" />
					<span class="text-card-foreground font-medium">Estado de Madurez LMAT 2.0</span>
				</div>
				<div class="flex items-center gap-2">
					<span
						class={`rounded-full px-3 py-1 text-xs font-medium ${BOM_MATURITY_COLORS[bom.maturityStatus || 'en_desarrollo']}`}
					>
						{BOM_MATURITY_LABELS[bom.maturityStatus || 'en_desarrollo']}
					</span>
					{#if spec}
						<a
							href={`/lmat/especificaciones/${spec.id}`}
							class="text-primary hover:underline flex items-center gap-1 text-xs"
						>
							Ver Especificacion <ExternalLink class="h-3 w-3" />
						</a>
					{/if}
				</div>
			</div>
			<div class="p-4">
				<p class="text-muted-foreground mb-4 text-sm">
					{BOM_MATURITY_DESCRIPTIONS[bom.maturityStatus || 'en_desarrollo']}
				</p>

				<!-- Departmental Validations -->
				<div class="mb-3 flex items-center gap-2">
					<Users class="text-muted-foreground h-4 w-4" />
					<span class="text-card-foreground text-sm font-medium">Validacion por Departamento</span>
					<button
						onclick={() => (showValidation = !showValidation)}
						class="text-primary hover:underline ml-auto text-xs"
					>
						{showValidation ? 'Ocultar detalles' : 'Ver detalles'}
					</button>
				</div>
				<div class="grid grid-cols-6 gap-2">
					{#each VALIDATION_DEPARTMENTS as dept}
						{@const validation = bom.departmentValidations?.find((v) => v.department === dept)}
						{@const status = validation?.status || 'pendiente'}
						{@const Icon =
							status === 'completado'
								? CircleCheck
								: status === 'rechazado'
									? XCircle
									: status === 'bloqueado'
										? Lock
										: Clock}
						<div
							class={`rounded-lg border p-2 ${status === 'completado' ? 'border-emerald-500/30 bg-emerald-500/5' : status === 'rechazado' ? 'border-destructive/30 bg-destructive/5' : 'border-border bg-secondary/50'}`}
						>
							<div class="mb-1 flex items-center justify-between">
								<span class="truncate text-[10px] font-medium">{dept}</span>
								<Icon
									class={`h-3 w-3 ${status === 'completado' ? 'text-emerald-500' : status === 'rechazado' ? 'text-destructive' : 'text-muted-foreground'}`}
								/>
							</div>
							<span class="text-muted-foreground text-[9px]">{DEPT_VALIDATION_LABELS[status]}</span>
						</div>
					{/each}
				</div>

				{#if showValidation}
					<div class="border-border mt-4 overflow-x-auto rounded-lg border border-border bg-secondary/30 p-3">
						<table class="w-full text-xs">
							<thead>
								<tr class="border-b border-border">
									<th class="text-left py-2 font-medium">Departamento</th>
									<th class="text-left py-2 font-medium">Estado</th>
									<th class="text-left py-2 font-medium">Validado por</th>
									<th class="text-left py-2 font-medium">Fecha</th>
									<th class="text-left py-2 font-medium">Notas</th>
								</tr>
							</thead>
							<tbody>
								{#each VALIDATION_DEPARTMENTS as dept}
									{@const validation = bom.departmentValidations?.find((v) => v.department === dept)}
									<tr class="border-b border-border/50">
										<td class="py-2 font-medium">{dept}</td>
										<td class="py-2">
											<span
												class={`rounded px-1.5 py-0.5 text-[10px] ${DEPT_VALIDATION_COLORS[validation?.status || 'pendiente']}`}
											>
												{DEPT_VALIDATION_LABELS[validation?.status || 'pendiente']}
											</span>
										</td>
										<td class="text-muted-foreground py-2">{validation?.validatedBy || '-'}</td>
										<td class="text-muted-foreground py-2"
											>{validation?.validatedAt ? formatDate(validation.validatedAt) : '-'}</td
										>
										<td class="text-muted-foreground py-2">{validation?.notes || '-'}</td>
									</tr>
								{/each}
							</tbody>
						</table>
						<div class="mt-3 flex justify-end">
							<a href="/lmat/validacion" class="text-primary hover:underline flex items-center gap-1 text-xs">
								Ir al Dashboard de Validacion <ExternalLink class="h-3 w-3" />
							</a>
						</div>
					</div>
				{/if}
			</div>
		</div>

		<!-- Related ECNs -->
		{#if relatedECNs.length > 0}
			<div class="border-chart-4/50 bg-chart-4/5 overflow-hidden rounded-lg border border-chart-4/50">
				<div class="border-chart-4/30 flex items-center gap-2 border-b border-chart-4/30 px-4 py-3">
					<FileWarning class="text-chart-4 h-4 w-4" />
					<span class="text-card-foreground font-medium">ECNs Relacionados ({relatedECNs.length})</span>
				</div>
				<div class="space-y-2 p-4">
					{#each relatedECNs as ecn}
						<a
							href={`/lmat/ecn/${ecn.id}`}
							class="border-border hover:bg-secondary/50 flex items-center justify-between rounded-lg border bg-card p-3 transition-colors"
						>
							<div>
								<span class="font-mono text-sm font-medium text-primary">{ecn.code}</span>
								<p class="text-muted-foreground mt-0.5 line-clamp-1 text-xs">{ecn.justification}</p>
							</div>
							<span
								class={`rounded-full px-2 py-0.5 text-[10px] font-medium ${ECN_STATUS_COLORS[ecn.status]}`}
							>
								{ECN_STATUS_LABELS[ecn.status]}
							</span>
						</a>
					{/each}
				</div>
			</div>
		{/if}

		<!-- Health + Stats -->
		<div class="grid grid-cols-2 gap-4 md:grid-cols-4">
			<div class="border-border rounded-lg border bg-card p-3">
				<span class="text-muted-foreground text-xs">Componentes</span>
				<p class="text-card-foreground text-xl font-bold">{bom.components.length}</p>
			</div>
			<div class="border-border rounded-lg border bg-card p-3">
				<span class="text-muted-foreground text-xs">Salud del BOM</span>
				<div class="mt-1 flex items-center gap-2">
					<div class="h-2 flex-1 rounded-full bg-secondary">
						<div
							class={`h-2 rounded-full ${bom.healthPercent >= 80 ? 'bg-primary' : bom.healthPercent >= 50 ? 'bg-chart-4' : 'bg-destructive'}`}
							style="width: {bom.healthPercent}%"
						/>
					</div>
					<span class="text-card-foreground font-mono text-sm font-bold">{bom.healthPercent}%</span>
				</div>
			</div>
			<div class="border-border rounded-lg border bg-card p-3">
				<span class="text-muted-foreground text-xs">Version</span>
				<p class="text-card-foreground font-mono text-xl font-bold">v{bom.version}</p>
			</div>
			<div class="border-border rounded-lg border bg-card p-3">
				<span class="text-muted-foreground text-xs">Revisiones</span>
				<p class="text-card-foreground text-xl font-bold">{bom.revisions.length}</p>
			</div>
		</div>

		<!-- View Mode Toggle -->
		<div class="flex items-center gap-2">
			<button
				onclick={() => (viewMode = 'jerarquico')}
				class={`flex items-center gap-1.5 rounded-md px-3 py-1.5 text-xs font-medium transition-colors ${viewMode === 'jerarquico' ? 'bg-primary text-primary-foreground' : 'bg-secondary text-foreground hover:bg-accent'}`}
			>
				<ListTree class="h-3.5 w-3.5" /> Vista Jerarquica
			</button>
			<button
				onclick={() => (viewMode = 'ingenieria')}
				class={`flex items-center gap-1.5 rounded-md px-3 py-1.5 text-xs font-medium transition-colors ${viewMode === 'ingenieria' ? 'bg-primary text-primary-foreground' : 'bg-secondary text-foreground hover:bg-accent'}`}
			>
				<List class="h-3.5 w-3.5" /> BOM Plano
			</button>
			<button
				onclick={() => (viewMode = 'surtimiento')}
				class={`flex items-center gap-1.5 rounded-md px-3 py-1.5 text-xs font-medium transition-colors ${viewMode === 'surtimiento' ? 'bg-primary text-primary-foreground' : 'bg-secondary text-foreground hover:bg-accent'}`}
			>
				<Boxes class="h-3.5 w-3.5" /> Por Celda/Kit
			</button>
			<button
				onclick={() => (showRevisions = !showRevisions)}
				class={`flex items-center gap-1.5 rounded-md px-3 py-1.5 text-xs font-medium transition-colors ${showRevisions ? 'bg-primary text-primary-foreground' : 'bg-secondary text-foreground hover:bg-accent'}`}
			>
				<GitBranch class="h-3.5 w-3.5" /> Historial ({bom.revisions.length})
			</button>
		</div>

		<!-- Hierarchical Tree View with Drag & Drop -->
		{#if viewMode === 'jerarquico'}
			<div class="border-border overflow-hidden rounded-lg border bg-card">
				<div class="border-b border-border flex items-center justify-between px-4 py-3">
					<div>
						<h3 class="text-card-foreground text-sm font-semibold">Vista Jerarquica - Kits y Componentes</h3>
						<p class="text-muted-foreground mt-0.5 text-xs">Arrastra y suelta para reorganizar la estructura</p>
					</div>
				</div>
				<div class="p-2">
					<BomTree
						components={bom.components}
						onReorder={handleReorder}
						readOnly={bom.status === 'aprobado' || bom.status === 'obsoleto'}
					/>
				</div>
			</div>
		{/if}

		<!-- Engineering View - Flat list -->
		{#if viewMode === 'ingenieria'}
			<div class="border-border overflow-hidden rounded-lg border bg-card">
				<div class="border-b border-border px-4 py-3">
					<h3 class="text-card-foreground text-sm font-semibold">BOM de Ingenieria - Listado concentrado</h3>
				</div>
				<div class="overflow-x-auto">
					<table class="w-full text-sm">
						<thead>
							<tr class="border-b border-border bg-secondary/50 text-left">
								<th class="w-8 px-4 py-2 text-xs font-medium text-muted-foreground">#</th>
								<th class="px-4 py-2 text-xs font-medium text-muted-foreground">Codigo</th>
								<th class="px-4 py-2 text-xs font-medium text-muted-foreground">Descripcion</th>
								<th class="px-4 py-2 text-right text-xs font-medium text-muted-foreground">Cantidad</th>
								<th class="px-4 py-2 text-xs font-medium text-muted-foreground">UdM</th>
								<th class="px-4 py-2 text-xs font-medium text-muted-foreground">Operacion</th>
								<th class="px-4 py-2 text-xs font-medium text-muted-foreground">Celda</th>
								<th class="px-4 py-2 text-xs font-medium text-muted-foreground">Datos</th>
							</tr>
						</thead>
						<tbody>
							{#each bom.components as comp, idx}
								<tr class="border-b border-border/50 hover:bg-secondary/30 transition-colors">
									<td class="px-4 py-2 text-xs text-muted-foreground">{idx + 1}</td>
									<td class="px-4 py-2">
										<a
											href={`/articulos/${comp.articleId}`}
											class="text-primary hover:underline font-mono text-xs"
										>
											{comp.articleCode}
										</a>
									</td>
									<td class="max-w-[250px] truncate px-4 py-2 text-card-foreground">{comp.articleDescription}</td>
									<td class="px-4 py-2 text-right font-mono text-card-foreground">{comp.quantity}</td>
									<td class="px-4 py-2 text-xs text-muted-foreground">{UDM_LABELS[comp.udm]}</td>
									<td class="px-4 py-2 text-xs text-muted-foreground">{comp.operation || '---'}</td>
									<td class="px-4 py-2 text-xs text-muted-foreground">{comp.cell}</td>
									<td class="px-4 py-2">
										{#if comp.hasCompleteData}
											<CircleCheck class="text-primary h-4 w-4" />
										{:else}
											<AlertTriangle class="text-chart-4 h-4 w-4" />
										{/if}
									</td>
								</tr>
							{/each}
						</tbody>
					</table>
				</div>
			</div>
		{/if}

		<!-- Surtimiento View - By cell/kit -->
		{#if viewMode === 'surtimiento'}
			<div class="flex flex-col gap-4">
				{#each componentsByCell as { cell, components }}
					{#if components.length > 0}
						<div class="border-border overflow-hidden rounded-lg border bg-card">
							<div class="border-b border-border flex items-center justify-between bg-secondary/30 px-4 py-2.5">
								<h3 class="text-card-foreground flex items-center gap-2 text-sm font-semibold">
									<Boxes class="text-primary h-4 w-4" /> {cell}
								</h3>
								<span class="text-muted-foreground text-xs">{components.length} componentes</span>
							</div>
							<div class="overflow-x-auto">
								<table class="w-full text-sm">
									<thead>
										<tr class="border-b border-border text-left">
											<th class="px-4 py-2 text-xs font-medium text-muted-foreground">Codigo</th>
											<th class="px-4 py-2 text-xs font-medium text-muted-foreground">Descripcion</th>
											<th class="px-4 py-2 text-right text-xs font-medium text-muted-foreground">Cantidad</th>
											<th class="px-4 py-2 text-xs font-medium text-muted-foreground">UdM</th>
											<th class="px-4 py-2 text-xs font-medium text-muted-foreground">Operacion</th>
											<th class="px-4 py-2 text-xs font-medium text-muted-foreground">Datos</th>
										</tr>
									</thead>
									<tbody>
										{#each components as comp}
											<tr class="border-b border-border/30 hover:bg-secondary/20 transition-colors">
												<td class="px-4 py-1.5">
													<a
														href={`/articulos/${comp.articleId}`}
														class="text-primary hover:underline font-mono text-xs"
													>
														{comp.articleCode}
													</a>
												</td>
												<td class="px-4 py-1.5 text-xs text-card-foreground">{comp.articleDescription}</td>
												<td class="px-4 py-1.5 text-right font-mono text-xs text-card-foreground">{comp.quantity}</td>
												<td class="px-4 py-1.5 text-xs text-muted-foreground">{UDM_LABELS[comp.udm]}</td>
												<td class="px-4 py-1.5 text-xs text-muted-foreground">{comp.operation || '---'}</td>
												<td class="px-4 py-1.5">
													{#if comp.hasCompleteData}
														<CircleCheck class="text-primary h-3.5 w-3.5" />
													{:else}
														<AlertTriangle class="text-chart-4 h-3.5 w-3.5" />
													{/if}
												</td>
											</tr>
										{/each}
									</tbody>
								</table>
							</div>
						</div>
					{/if}
				{/each}
				{#if unassigned.length > 0}
					<div class="border-chart-4/30 bg-card overflow-hidden rounded-lg border border-chart-4/30">
						<div class="bg-chart-4/10 border-b border-border border-chart-4/30 px-4 py-2.5">
							<h3 class="text-chart-4 text-sm font-semibold">Sin celda asignada ({unassigned.length})</h3>
						</div>
						<div class="overflow-x-auto">
							<table class="w-full text-sm">
								<tbody>
									{#each unassigned as comp}
										<tr class="border-b border-border/30">
											<td class="px-4 py-1.5 font-mono text-xs text-primary">{comp.articleCode}</td>
											<td class="px-4 py-1.5 text-xs text-card-foreground">{comp.articleDescription}</td>
											<td class="px-4 py-1.5 text-right font-mono text-xs text-card-foreground">{comp.quantity}</td>
										</tr>
									{/each}
								</tbody>
							</table>
						</div>
					</div>
				{/if}
			</div>
		{/if}

		<!-- Revision History -->
		{#if showRevisions}
			<div class="border-border overflow-hidden rounded-lg border bg-card">
				<div class="border-b border-border flex items-center justify-between px-4 py-3">
					<div class="flex items-center gap-2">
						<History class="text-primary h-4 w-4" />
						<h3 class="text-card-foreground text-sm font-semibold">Historial de Revisiones</h3>
					</div>
					<span class="text-muted-foreground text-xs">{bom.revisions.length} versiones</span>
				</div>
				{#if bom.revisions.length > 0}
					<div class="flex flex-col divide-y divide-border/30">
						{#each [...bom.revisions].reverse() as rev}
							<div
								class={`px-4 py-4 ${viewingRevision === rev.id || comparingRevision === rev.id ? 'border-l-2 border-primary bg-primary/5' : ''}`}
							>
								<!-- Header de la revision -->
								<div class="mb-3 flex items-center justify-between">
									<div class="flex items-center gap-2">
										<span
											class={`rounded px-2 py-1 font-mono text-xs font-bold ${rev.version === bom.version ? 'bg-primary text-primary-foreground' : 'bg-secondary text-muted-foreground'}`}
										>
											v{rev.version}
										</span>
										{#if rev.version === bom.version}
											<span class="rounded bg-emerald-400/15 px-1.5 py-0.5 text-[10px] font-medium text-emerald-400"
												>ACTUAL</span
											>
										{/if}
									</div>
									<div class="flex items-center gap-2 text-xs text-muted-foreground">
										<span>{rev.changedBy}</span>
										<span class="text-muted-foreground/50">|</span>
										<span>{formatDate(rev.changedAt)}</span>
									</div>
								</div>

								<!-- Motivo del cambio -->
								<p class="text-card-foreground mb-3 border-l-2 border-muted pl-1 text-sm">{rev.changeReason}</p>

								<!-- Changelog narrativo -->
								{#if rev.diff.length > 0}
									<div class="mb-3 rounded-md bg-secondary/30 p-3">
										<p class="text-muted-foreground mb-2 text-xs font-medium">Cambios realizados:</p>
										<ul class="space-y-1.5">
											{#each rev.diff as d, i}
												<li class="text-card-foreground flex items-start gap-2 text-xs">
													<span
														class={`flex-shrink-0 mt-0.5 h-1.5 w-1.5 rounded-full ${d.type === 'added' ? 'bg-emerald-400' : d.type === 'removed' ? 'bg-destructive' : 'bg-chart-4'}`}
													/>
													<span>
														{#if d.type === 'added'}
															Se agrego <span class="font-medium text-emerald-400">{d.articleCode}</span> ({d.articleDescription})
														{:else if d.type === 'removed'}
															Se elimino <span class="font-medium text-destructive">{d.articleCode}</span> ({d.articleDescription})
														{:else if d.type === 'modified'}
															Se modifico <span class="font-medium text-chart-4">{d.articleCode}</span>: {d.field}
															<span class="line-through text-muted-foreground">{d.oldValue}</span>
															<ChevronRight class="inline h-3 w-3" />
															<span class="font-medium">{d.newValue}</span>
														{/if}
													</span>
												</li>
											{/each}
										</ul>
									</div>
								{:else}
									<p class="text-muted-foreground mb-3 rounded-md bg-secondary/30 px-3 py-2 text-xs">
										Version creada como snapshot - sin cambios registrados respecto a la anterior
									</p>
								{/if}

								<!-- Botones de accion -->
								<div class="flex items-center gap-2">
									<button
										onclick={() => (viewingRevision = viewingRevision === rev.id ? null : rev.id)}
										class={`flex items-center gap-1.5 rounded px-2.5 py-1.5 text-xs font-medium transition-colors ${viewingRevision === rev.id ? 'bg-primary text-primary-foreground' : 'bg-secondary text-foreground hover:bg-accent'}`}
									>
										<Eye class="h-3 w-3" />
										{viewingRevision === rev.id ? 'Ocultar snapshot' : 'Ver snapshot'}
									</button>
									{#if rev.version !== bom.version}
										<button
											onclick={() => (comparingRevision = comparingRevision === rev.id ? null : rev.id)}
											class={`flex items-center gap-1.5 rounded px-2.5 py-1.5 text-xs font-medium transition-colors ${comparingRevision === rev.id ? 'bg-chart-4 text-foreground' : 'bg-secondary text-foreground hover:bg-accent'}`}
										>
											<GitBranch class="h-3 w-3" />
											{comparingRevision === rev.id ? 'Cerrar comparacion' : 'Comparar con actual'}
										</button>
									{/if}
								</div>
							</div>
						{/each}
					</div>
				{:else}
					<div class="px-4 py-6 text-center text-sm text-muted-foreground">
						No hay revisiones registradas. Usa el boton "Crear Version" para guardar el estado actual.
					</div>
				{/if}
			</div>
		{/if}

		<!-- Viewing old revision snapshot -->
		{#if selectedRevision}
			<div class="border-primary/50 overflow-hidden rounded-lg border-2 bg-card">
				<div class="bg-primary/10 border-b border-border flex items-center justify-between px-4 py-3">
					<div class="flex items-center gap-2">
						<History class="text-primary h-4 w-4" />
						<h3 class="text-card-foreground text-sm font-semibold">
