											colorClass={approval.status === 'aprobado' ? 'bg-emerald-500/15 text-emerald-400' : approval.status === 'rechazado' ? 'bg-destructive/15 text-destructive-foreground' : 'bg-muted text-muted-foreground'}
										/>
									{/if}
								</div>

