		return state.boms.filter((b) => b.components.some((c) => c.articleId === oldArticleId));
	});

	const oldArticle = $derived(state.articles.find((a) => a.id === oldArticleId));
	const newArticle = $derived(state.articles.find((a) => a.id === newArticleId));

	function toggleBom(id: string) {
		selectedBomIds = selectedBomIds.includes(id)
			? selectedBomIds.filter((b) => b !== id)
			: [...selectedBomIds, id];
	}

	function selectAll() {
		selectedBomIds = affectedBOMs.map((b) => b.id);
	}
	function deselectAll() {
		selectedBomIds = [];
	}

	function applyChange() {
		if (!oldArticleId || !newArticleId || selectedBomIds.length === 0 || !reason.trim()) return;
		store.dispatch({
			type: 'MASS_CHANGE_COMPONENT',
			payload: { oldArticleId, newArticleId, bomIds: selectedBomIds, reason: reason.trim() }
		});
		store.dispatch({
			type: 'ADD_AUDIT_LOG',
			payload: {
				id: generateId(),
				userId: state.currentUser.id,
				userName: state.currentUser.name,
				entity: 'BOM',
				entityId: 'mass-change',
				action: 'cambio_masivo',
				field: 'componente',
				oldValue: oldArticle?.code || '',
				newValue: `${newArticle?.code} en ${selectedBomIds.length} BOMs`,
				timestamp: new Date().toISOString()
			}
		});
		applied = true;
	}

	function reset() {
		applied = false;
		oldArticleId = null;
		newArticleId = null;
		selectedBomIds = [];
		reason = '';
		oldQuery = '';
		newQuery = '';
	}
</script>

